    @Test
    @DisplayName("Null visitor throws IllegalArgumentException at entry")
    public void test_TC01_O1() {
        // Passing null visitor => Validate.notNull(visitor) should throw
        NodeVisitor visitor = null;
        Node root = new TextNode("text"); // Changed constructor to match expected parameters
        assertThrows(IllegalArgumentException.class, () -> NodeTraversor.traverse(visitor, (Node) root));
    }

